import os
import shutil
import logging
import psutil

# Set up logging configuration
logging.basicConfig(filename='home_folder_cleanup.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def get_unused_files(directory):
    """
    Returns a list of files in the given directory that are not in use by any running processes.
    """
    used_files = set()
    for proc in psutil.process_iter(['pid', 'open_files']):
        try:
            for file in proc.open_files():
                if file.path.startswith(directory):
                    used_files.add(file.path)
        except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
            pass
    return [file for file in os.listdir(directory) if file not in used_files]

def clean_home_folder(directory):
    """
    Removes any redundant files from the given directory.
    """
    logging.info(f"Cleaning up {directory}...")
    for file in get_unused_files(directory):
        try:
            os.remove(file)
            logging.info(f"Removed {file}")
        except OSError as e:
            logging.error(f"Error removing {file}: {e}")

def main():
    home_directory = os.path.expanduser('~')
    clean_home_folder(home_directory)

if __name__ == "__main__":
    main()
