import os
import logging
import shutil

# Set up logging
logging.basicConfig(filename='cleanup.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def is_essential_file(filename):
    # List of essential files
    essential_files = ['*.log', '*.tmp', '*.bak', '*.swp', '*.o', '*.obj', '*.class']
    return not any(filename.endswith(file) for file in essential_files)

def clear_directory(path):
    try:
        for item in os.listdir(path):
            item_path = os.path.join(path, item)
            if os.path.isfile(item_path):
                if not is_essential_file(item):
                    try:
                        os.remove(item_path)
                        logging.info(f'Removed file: {item_path}')
                    except Exception as e:
                        logging.error(f'Failed to remove file: {item_path}. Error: {e}')
            elif os.path.isdir(item_path):
                clear_directory(item_path)
    except Exception as e:
        logging.error(f'Failed to clear directory: {path}. Error: {e}')

def main():
    user_home_dir = '/home/user'  # Replace with the actual user's home directory
    clear_directory(user_home_dir)

if __name__ == '__main__':
    main()
